mapper.select:
SELECT item.id, item.stocktake_id, item.stocktake_no, item.part_id, item.part_code, item.part_name, item.part_model, item.part_type, CASE item.part_type WHEN 'fan' THEN '风扇' WHEN 'capacitor' THEN '电容' WHEN 'board' THEN '板卡' WHEN 'other' THEN '其他' ELSE '未知' END AS part_type_desc, item.unit, item.unit_price, item.system_quantity, item.actual_quantity, item.diff_quantity, item.diff_type, CASE item.diff_type WHEN 0 THEN '无差异' WHEN 1 THEN '盘盈' WHEN 2 THEN '盘亏' ELSE '未知' END AS diff_type_desc, item.diff_amount, item.storage_location, item.remark, item.create_time, item.update_time FROM spare_part_stocktake_item item WHERE item.deleted = 0 AND item.stocktake_id = #{stocktakeId}
AND item.diff_type = #{diffType}
ORDER BY item.part_code
